arguments.new_str:
protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // [EF Core 9 – HasIndex throws] Cosmos DB indexing is managed via
    // the container's indexing policy, not EF Core. Removed HasIndex call.

    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // [EF Core 9 – Discriminator renamed to $type] Preserve the
        // legacy property name so existing 500K documents stay readable
        // and direct SQL queries referencing c.Discriminator keep working.
        entity.HasDiscriminator<string>("Discriminator");

        // [EF Core 9 – id no longer contains discriminator] Preserve the
        // legacy "Product|123" id format so FindAsync / point-reads match
        // existing documents written by EF Core 8.
        entity.HasRootDiscriminatorInJsonId(true);
    });
}

arguments.old_str:
class CosmosQuery
{
    void FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
        // Also uses sync APIs
        var products = ctx.Products.Where(p => p.Sku == "ABC").ToList();
    }
}

arguments.new_str:
using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // [EF Core 9 – Sync I/O throws] The Cosmos provider no longer supports
    // synchronous calls; switched to async.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still valid because we explicitly configured
        // HasDiscriminator<string>("Discriminator") to keep the legacy property name.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

